def _u(*chunks: str) -> list[str]:
    """Split comma-separated entries, trimming and preserving first occurrence."""
    result: list[str] = []
    seen: set[str] = set()
    for chunk in chunks:
        for item in chunk.split(","):
            item = " ".join(item.strip().split())
            if item and item.casefold() not in seen:
                result.append(item)
                seen.add(item.casefold())
    return result


