    for category, levels in BANKS.items():
        entries = [entry for level in levels.values() for entry in level]
        print(
            f"{category}: "
            + ", ".join(f"{level}={len(words)}" for level, words in levels.items())
        )
        assert len({entry.casefold() for entry in entries}) == len(entries), (
            f"{category}: duplicate entries"
        )
        for level, words in levels.items():
            if len(words) < 30:
                print(f"WARN {category}/{level}: {len(words)}")
    print("OK", sum(len(w) for c in BANKS.values() for w in c.values()), "raw entries")
